const action = $input.item.json.action || '';
const match = action.match(/^ADD_(\d+)$/);
if (!match) {
  return { 
    ...$input.item.json, 
    error: 'INVALID_ITEM',
    error_msg: '❌ Invalid menu item selection'
  };
}
return { 
  ...$input.item.json, 
  item_id: parseInt(match[1])
};

const item = $input.all()[0]?.json;
if (!item || !item.id) {
  return { 
    ...$input.first().json, 
    error: 'ITEM_NOT_FOUND',
    error_msg: '❌ This item is no longer available'
  };
}

const session = $input.first().json.session || {};
const cart = session.cart || [];

const existing = cart.find(i => i.id === item.id);
if (existing) {
  existing.quantity += 1;
} else {
  cart.push({
    id: item.id,
    name: item.name,
    price: item.price,
    quantity: 1
  });
}

const subtotal = cart.reduce((sum, i) => sum + (i.price * i.quantity), 0);
const tax = Math.round(subtotal * 0.05);
const total = subtotal + tax;

return {
  ...$input.first().json,
  session: { ...session, cart: cart },
  cart: cart,
  subtotal: subtotal,
  tax: tax,
  total: total,
  added_item: item
};

