const orders = $input.all();
if (orders.length === 0) {
  return { 
    ...$input.first().json, 
    error: 'NO_HISTORY',
    error_msg: '📋 No order history found'
  };
}

const history = orders.map(o => {
  const date = new Date(o.json.created_at).toLocaleString('en-IN', {timeZone: 'Asia/Kolkata', dateStyle: 'short', timeStyle: 'short'});
  return `• ${o.json.order_id} - ₹${o.json.total} (${date})`;
}).join('\n');

return {
  ...$input.first().json,
  history_display: history
};

const text = ($input.item.json.text || '').toString();
const match = text.match(/REMOVE\s+(\d+)/i);
if (!match) {
  return { 
    ...$input.item.json, 
    error: 'INVALID_REMOVE',
    error_msg: '❌ Please use format: REMOVE <item_id>'
  };
}

const itemId = parseInt(match[1]);
const session = $input.item.json.session || {};
const cart = session.cart || [];

const itemIndex = cart.findIndex(i => i.id === itemId);
if (itemIndex === -1) {
  return { 
    ...$input.item.json, 
    error: 'ITEM_NOT_IN_CART',
    error_msg: '❌ Item not found in cart'
  };
}

const removed = cart.splice(itemIndex, 1)[0];

const subtotal = cart.reduce((sum, i) => sum + (i.price * i.quantity), 0);
const tax = Math.round(subtotal * 0.05);
const total = subtotal + tax;

return {
  ...$input.item.json,
  session: { ...session, cart: cart },
  cart: cart,
  subtotal: subtotal,
  tax: tax,
  total: total,
  removed_item: removed
};
